import React, { useMemo } from 'react';
import {
  Card,
  Stack,
  Row,
  Text,
  Divider,
  Badge,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Props {
  /** City name */
  city?: string;
  /** Current temperature */
  temperature?: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition?: string;
  /** Humidity percentage */
  humidity?: number;
  /** Wind speed */
  windSpeed?: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast?: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * Maps weather condition strings to appropriate emoji icons
 */
function getWeatherEmoji(condition: string): string {
  const conditionMap: Record<string, string> = {
    'sunny': '☀️',
    'clear': '☀️',
    'cloudy': '☁️',
    'overcast': '☁️',
    'rainy': '🌧️',
    'rain': '🌧️',
    'stormy': '⛈️',
    'storm': '⛈️',
    'snowy': '❄️',
    'snow': '❄️',
    'windy': '💨',
    'wind': '💨',
    'foggy': '🌫️',
    'fog': '🌫️',
    'partly cloudy': '⛅',
    'partly_cloudy': '⛅',
    'drizzle': '🌦️',
    'humid': '💧',
    'haze': '🌫️',
  };
  return conditionMap[condition.toLowerCase()] || '🌤️';
}

/**
 * Forecast item sub-component for 5-day strip
 */
function ForecastItem({
  day = 'Day',
  icon = '🌤️',
  high = '--',
  low = '--',
  index = 0,
}: {
  day?: string;
  icon?: string;
  high?: number | string;
  low?: number | string;
  index?: number;
}) {
  const { motionEnabled } = useMotion();
  const animationDelay = motionEnabled ? `${index * 50}ms` : '0ms';

  return (
    <div
      style={{
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        gap: 'var(--ggui-spacing-2, 8px)',
        padding: 'var(--ggui-spacing-2, 8px)',
        borderRadius: 'var(--ggui-shape-radius-md, 8px)',
        backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
        border: '1px solid var(--ggui-color-outline, #d4d4d8)',
        minWidth: '70px',
        textAlign: 'center',
        animation: motionEnabled ? animation.slideInUp : 'none',
        animationDelay,
        animationFillMode: 'both',
      }}
    >
      <Text
        variant="caption"
        weight="medium"
        color="var(--ggui-color-onSurfaceVariant, #52525b)"
      >
        {day}
      </Text>
      <div style={{ fontSize: '28px' }}>{icon}</div>
      <div style={{ display: 'flex', gap: 'var(--ggui-spacing-1, 4px)', fontSize: 'var(--ggui-font-size-xs, 12px)' }}>
        <Text
          variant="caption"
          weight="semibold"
          color="var(--ggui-color-primary-600, #0284c7)"
        >
          {high}°
        </Text>
        <Text
          variant="caption"
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
        >
          {low}°
        </Text>
      </div>
    </div>
  );
}

/**
 * WeatherCard Component
 *
 * Displays current weather information and a 5-day forecast.
 * All data is provided via props (no hardcoded values).
 * Uses design system tokens for all colors, spacing, and typography.
 */
export default function WeatherCard({
  city = 'Unknown',
  temperature = 20,
  condition = 'Clear',
  humidity = 50,
  windSpeed = 10,
  unit = '°C',
  forecast = [],
}: Props) {
  const { motionEnabled } = useMotion();
  const conditionEmoji = useMemo(() => getWeatherEmoji(condition), [condition]);

  // Ensure forecast has exactly 5 items (pad with empty items if needed)
  const forecastData = useMemo(() => {
    const padded = [...(forecast || [])];
    const daysOfWeek = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];

    while (padded.length < 5) {
      const idx = padded.length;
      padded.push({
        day: daysOfWeek[idx % 7],
        icon: '🌤️',
        high: '--',
        low: '--',
      });
    }

    return padded.slice(0, 5);
  }, [forecast]);

  return (
    <>
      <MotionKeyframes />
      <Card
        padding="24"
        shadow="md"
        border={true}
        style={{
          animation: motionEnabled ? animation.fadeIn : 'none',
          backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
        }}
        role="region"
        aria-label={`Weather forecast for ${city}`}
      >
        <Stack direction="vertical" gap={16}>
          {/* Header: City & Condition */}
          <div
            style={{
              backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
              borderRadius: 'var(--ggui-shape-radius-md, 8px)',
              padding: 'var(--ggui-spacing-4, 16px)',
              borderLeft: '4px solid var(--ggui-color-primary-500, #0ea5e9)',
            }}
          >
            <Row gap={8} justify="start" align="center">
              <Stack direction="vertical" gap={4}>
                <Text
                  variant="h2"
                  weight="bold"
                  color="var(--ggui-color-onSurface, #18181b)"
                >
                  {city}
                </Text>
                <Text
                  variant="body"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  {condition}
                </Text>
              </Stack>
            </Row>
          </div>

          {/* Current Temperature Display */}
          <div
            style={{
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              gap: 'var(--ggui-spacing-4, 16px)',
              padding: 'var(--ggui-spacing-4, 16px)',
            }}
          >
            <div style={{ fontSize: '64px', lineHeight: '1' }}>
              {conditionEmoji}
            </div>
            <Stack direction="vertical" gap={4} align="start">
              <div style={{ display: 'flex', alignItems: 'baseline', gap: 'var(--ggui-spacing-2, 8px)' }}>
                <Text
                  variant="h1"
                  weight="bold"
                  color="var(--ggui-color-primary-600, #0284c7)"
                  style={{
                    fontSize: 'var(--ggui-font-size-4xl, 36px)',
                    lineHeight: '1',
                  }}
                >
                  {Math.round(temperature)}
                </Text>
                <Badge variant="primary" size="sm">
                  {unit}
                </Badge>
              </div>
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Feels like {Math.round(temperature - 2)}°
              </Text>
            </Stack>
          </div>

          <Divider margin={12} orientation="horizontal" />

          {/* Current Metrics: Humidity & Wind Speed */}
          <Row gap={24} justify="between" align="stretch">
            {/* Humidity */}
            <div
              style={{
                flex: 1,
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                gap: 'var(--ggui-spacing-2, 8px)',
                padding: 'var(--ggui-spacing-4, 16px)',
                backgroundColor: 'var(--ggui-color-surface, #fafafa)',
                borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                border: '1px solid var(--ggui-color-outline, #d4d4d8)',
              }}
              role="region"
              aria-label={`Humidity ${humidity} percent`}
            >
              <Text
                variant="caption"
                weight="medium"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Humidity
              </Text>
              <Text
                variant="h3"
                weight="bold"
                color="var(--ggui-color-primary-600, #0284c7)"
              >
                {humidity}%
              </Text>
            </div>

            {/* Wind Speed */}
            <div
              style={{
                flex: 1,
                display: 'flex',
                flexDirection: 'column',
                alignItems: 'center',
                gap: 'var(--ggui-spacing-2, 8px)',
                padding: 'var(--ggui-spacing-4, 16px)',
                backgroundColor: 'var(--ggui-color-surface, #fafafa)',
                borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                border: '1px solid var(--ggui-color-outline, #d4d4d8)',
              }}
              role="region"
              aria-label={`Wind speed ${windSpeed} kilometers per hour`}
            >
              <Text
                variant="caption"
                weight="medium"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Wind Speed
              </Text>
              <Text
                variant="h3"
                weight="bold"
                color="var(--ggui-color-primary-600, #0284c7)"
              >
                {windSpeed}
              </Text>
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                km/h
              </Text>
            </div>
          </Row>

          <Divider margin={12} orientation="horizontal" />

          {/* 5-Day Forecast Strip */}
          <Stack direction="vertical" gap={8}>
            <Text
              variant="label"
              weight="semibold"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              5-Day Forecast
            </Text>
            <Row
              gap={12}
              justify="start"
              align="stretch"
              wrap={true}
              style={{
                overflowX: 'auto',
                paddingBottom: 'var(--ggui-spacing-2, 8px)',
              }}
            >
              {forecastData.map((item, index) => (
                <ForecastItem
                  key={`${item.day}-${index}`}
                  day={item.day}
                  icon={item.icon || getWeatherEmoji(item.day || '')}
                  high={item.high}
                  low={item.low}
                  index={index}
                />
              ))}
            </Row>
          </Stack>
        </Stack>
      </Card>
    </>
  );
}

