import React from 'react';
import { 
  Container, 
  Card, 
  Stack, 
  Row, 
  Text, 
  Divider, 
  Box 
} from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * WeatherCard Component
 * A template for displaying current weather data and a 5-day forecast.
 */
export default function WeatherCard({
  city = 'Unknown City',
  temperature = 0,
  condition = 'Clear',
  humidity = 0,
  windSpeed = 0,
  unit = '°C',
  forecast = []
}: Props) {

  // Internal helper to map condition strings to display emojis if icon isn't provided
  const getConditionEmoji = (cond: string) => {
    const c = (cond || '').toLowerCase();
    if (c.includes('sun') || c.includes('clear')) return '☀️';
    if (c.includes('cloud')) return '☁️';
    if (c.includes('rain') || c.includes('shower')) return '🌧️';
    if (c.includes('thunder')) return '⛈️';
    if (c.includes('snow')) return '❄️';
    return '⛅';
  };

  return (
    <Container maxWidth="sm">
      <Card 
        padding="var(--ggui-spacing-6, 24px)" 
        shadow="md"
        style={{
          backgroundColor: 'var(--ggui-color-primary-50, #f0f9ff)',
          borderColor: 'var(--ggui-color-primary-200, #bae6fd)',
          transition: 'transform 0.2s ease-in-out'
        }}
      >
        <Stack gap={20}>
          {/* Header Section */}
          <Stack gap={2}>
            <Text variant="h2" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
              {city}
            </Text>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Current Conditions
            </Text>
          </Stack>

          {/* Main Weather Display */}
          <Row justify="between" align="center">
            <Stack align="start" gap={4}>
              <div 
                style={{ fontSize: '3rem', lineHeight: 1 }} 
                aria-hidden="true"
              >
                {getConditionEmoji(condition)}
              </div>
              <Text variant="body" weight="medium" color="var(--ggui-color-onSurface, #18181b)">
                {condition}
              </Text>
            </Stack>

            <Text 
              variant="h1" 
              weight="bold" 
              color="var(--ggui-color-primary-600, #0284c7)"
              style={{ fontSize: '4rem', lineHeight: 1 }}
            >
              {temperature}{unit}
            </Text>
          </Row>

          {/* Secondary Details */}
          <Row gap={24}>
            <Stack gap={2}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Humidity</Text>
              <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{humidity}%</Text>
            </Stack>
            <Stack gap={2}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">Wind Speed</Text>
              <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">{windSpeed} km/h</Text>
            </Stack>
          </Row>

          <Divider margin={8} />

          {/* Forecast Strip */}
          <Box paddingY="var(--ggui-spacing-2, 8px)">
            <Row justify="between" align="center">
              {forecast && forecast.length > 0 ? (
                forecast.slice(0, 5).map((day, index) => (
                  <Stack key={`forecast-${index}`} align="center" gap={8} style={{ flex: 1 }}>
                    <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {day.day}
                    </Text>
                    <div 
                      style={{ fontSize: '1.5rem' }} 
                      aria-hidden="true"
                    >
                      {day.icon || getConditionEmoji(condition)}
                    </div>
                    <Stack align="center" gap={0}>
                      <Text variant="caption" weight="bold" color="var(--ggui-color-onSurface, #18181b)">
                        {day.high}{unit}
                      </Text>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {day.low}{unit}
                      </Text>
                    </Stack>
                  </Stack>
                ))
              ) : (
                <Text variant="caption" align="center" style={{ width: '100%' }} color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  No forecast available
                </Text>
              )}
            </Row>
          </Box>
        </Stack>
      </Card>
    </Container>
  );
}
